const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line);
        if (inputLines.length === 2) {
            rl.close();
        }
    });

    rl.on('close', () => {
        let [n, k] = inputLines[0].split(' ').map(Number);
        let array = inputLines[1].split(' ').map(Number);

        let found = false;

        // Use a for loop to search for the element in the array
        for (let i = 0; i < n; ++i) {
            if (array[i] === k) {
                found = true;
                break;
            }
        }

        // Print the result using if-else
        if (found) {
            console.log("Yes");
        } else {
            console.log("No");
        }
    });
}

